/**
 * External dependencies
 */
import { useMemo } from '@googleforcreators/react';
import {
  convertToCSS,
  generatePatternStyles,
} from '@googleforcreators/patterns';

/**
 * Internal dependencies
 */
import { MULTIPLE_VALUE } from '../../../constants';

/**
 * Memoizes the common color value.
 *
 * @param {Array.<Object>} list List of objects.
 * @param {string} property Property to check on all objects.
 * @return {Object} Found common color value.
 */
function useCommonColorValue(list, property) {
  return useMemo(() => {
    const allValues = list.map((element) => element[property]);
    if (allValues.length === 0) {
      return null;
    }
    if (allValues.length === 1) {
      return allValues[0];
    }
    const uniqueValues = {};
    allValues.forEach((value) => {
      const serialized = convertToCSS(generatePatternStyles(value));
      if (!(serialized in uniqueValues)) {
        uniqueValues[serialized] = value;
      }
    });
    return Object.keys(uniqueValues).length === 1
      ? Object.values(uniqueValues)[0]
      : MULTIPLE_VALUE;
  }, [list, property]);
}

export default useCommonColorValue;
